	#END	
	
	# ===================AREA======================================= 	
	LAYER 
		NAME 'ARA'
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		INCLUDE "datashare.inc"
		#PROCESSING "NATIVE_FILTER=%provinceFilter%"
		DATA 'sp_geometry FROM "vw_att_details_area_map" USING UNIQUE system_id USING srid=4326'
		FILTER  (provinceFilter) 
		
		VALIDATION		
			'provinceFilter'   '.*'	
		END 
		METADATA
			'ows_title' 'Area'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 30
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END
		CLASS
			NAME 'Area' 
			STYLE
				WIDTH 1
				OUTLINECOLOR 0 0 0
				COLOR 26 149 190
			END
		END
	END
	
